import logging

def log_calls(func):
    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        logging.info(f'Calling {func.__name__}({args}, {kwargs})')
        result = func(*args, **kwargs)
        logging.info(f'{func.__name__} returned {result}')
        return result
    return wrapper

